{
    $user ??= User::factory()->create();

    $storage = app(SecureTokenStorage::class);

    if (! $storage instanceof InMemorySecureTokenStorage) {
        $storage = new InMemorySecureTokenStorage;
        app()->instance(SecureTokenStorage::class, $storage);
    }

    $storage->put($token);

